pragma solidity ^0.8.9;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract MyNFT is ERC721, Ownable {
    enum Stage { WhitelistActivation, WhitelistingPhase, MintingPhase }
    Stage public currentStage = Stage.WhitelistActivation;

    struct WhitelistTier {
        uint256 allowance;
        uint256 price;
    }

    mapping(address => WhitelistTier) public whitelist;
    uint256 public totalSupply;
    uint256 public maxSupply;

    event MintEvent(address indexed minter, uint256 tokenId);

    constructor(uint256 _maxSupply, string memory _name, string memory _symbol)
        ERC721(_name, _symbol) {
        maxSupply = _maxSupply;
    }

    modifier onlyWhitelisted() {
        require(whitelist[msg.sender].allowance > 0, "Not whitelisted");
        _;
    }

    function setStage(Stage _stage) external onlyOwner {
        currentStage = _stage;
    }

    function addWhitelist(address[] calldata addresses, uint256[] calldata allowances, uint256[] calldata prices) external onlyOwner {
        require(addresses.length == allowances.length && addresses.length == prices.length, "Input arrays must be of same length");
        for (uint256 i = 0; i < addresses.length; i++) {
            whitelist[addresses[i]] = WhitelistTier(allowances[i], prices[i]);
        }
    }

    function removeWhitelist(address[] calldata addresses) external onlyOwner {
        for (uint256 i = 0; i < addresses.length; i++) {
            delete whitelist[addresses[i]];
        }
    }

    function mint(uint256 numberOfTokens) external payable onlyWhitelisted {
        require(currentStage == Stage.MintingPhase, "Minting is not active");
        require(numberOfTokens <= whitelist[msg.sender].allowance, "Exceeds allowance");
        require(msg.value >= numberOfTokens * whitelist[msg.sender].price, "Insufficient payment");

        for (uint256 i = 0; i < numberOfTokens; i++) {
            require(totalSupply < maxSupply, "Max supply reached");
            totalSupply++;
            _safeMint(msg.sender, totalSupply);
            emit MintEvent(msg.sender, totalSupply);
        }

        whitelist[msg.sender].allowance -= numberOfTokens;
    }

    function adminMint(address recipient, uint256 numberOfTokens) external onlyOwner {
        require(totalSupply + numberOfTokens <= maxSupply, "Max supply reached");
        for (uint256 i = 0; i < numberOfTokens; i++) {
            totalSupply++;
            _safeMint(recipient, totalSupply);
            emit MintEvent(recipient, totalSupply);
        }
    }

    // Removed unnecessary receive function
    // receive() external payable {}

    function _beforeTokenTransfer(
        address from,
        address to,
        uint256 tokenId
    ) internal override {
        super._beforeTokenTransfer(from, to, tokenId);
        if (from != address(0)) {
            totalSupply--;
        }
        if (to != address(0)) {
            totalSupply++;
        }
    }
}
```

